  slug=$(echo $file | sed 's|.*/||;s|/page.*||')
  name=$(grep -oP 'name="[^"]*"' "$file" | head -1)
  emoji=$(grep -oP 'emoji="[^"]*"' "$file" | head -1)
  desc=$(grep -oP 'description="[^"]*"' "$file" | head -1)

  # Map slug to hero image
  case "$slug" in
    pesca) hero="hero-pesca" ;;
    accesorios) hero="hero-outdoor" ;;
    autos) hero="hero-autos" ;;
    motos) hero="hero-motos" ;;
    campo) hero="hero-campo" ;;
  esac

  sed -i "s|slug=\"$slug\" $name $emoji $desc />|slug=\"$slug\" $name $emoji $desc heroImage=\"/images/marketing/$hero.png\" />|" "$file"
  echo "Updated: $file with hero-$hero"
done", "timeout": 15}

